const DEPTS = [
  "CEO Office - CPD",
  "Finance & Controlling",
  "OHS",
  "Commercial - M&S",
  "Commercial - Logistics",
  "HR",
  "SRB - Plant 2",
  "SRB - Plant 3",
];

const DEPT_SHORT = {
  "CEO Office - CPD": "CEO/CPD",
  "Finance & Controlling": "F&C",
  "OHS": "OHS",
  "Commercial - M&S": "Com M&S",
  "Commercial - Logistics": "Com Logistics",
  "HR": "HR",
  "SRB - Plant 2": "SRB P2",
  "SRB - Plant 3": "SRB P3",
};

const ST = ["On-Track", "Risk of delay", "High risk", "No activities"];
// "No activities" counts as On-Track for progress/summary purposes
const isOnTrack = s => s === "On-Track" || s === "No activities";

const SC = {
  "On-Track":      { bg:"#EAF3DE", c:"#2D5A0E", dot:"#639922", bd:"#C0DD97" },
  "Risk of delay": { bg:"#FAEEDA", c:"#7A4A08", dot:"#EF9F27", bd:"#FAC775" },
  "High risk":     { bg:"#FCEBEB", c:"#8B2020", dot:"#E24B4A", bd:"#F7C1C1" },
  "No activities": { bg:"#F1EFE8", c:"#4A4944", dot:"#888780", bd:"#D3D1C7" },
};

const today = () => new Date().toISOString().split("T")[0];
const nowTs = () => new Date().toLocaleString("en-GB", {
  day:"2-digit", month:"short", year:"numeric", hour:"2-digit", minute:"2-digit"
});
const fmt = d => {
  if (!d) return "—";
  const s = String(d).trim();
  return s.length >= 10 ? s.slice(0,10) : (s || "—");
};

// counts: "No activities" treated as on-track for %
const counts = arr => ({
  "On-Track":      arr.filter(r => r.status === "On-Track").length,
  "Risk of delay": arr.filter(r => r.status === "Risk of delay").length,
  "High risk":     arr.filter(r => r.status === "High risk").length,
  "No activities": arr.filter(r => r.status === "No activities").length,
  _onTrackEff:     arr.filter(r => isOnTrack(r.status)).length,
});

const BASE = 12; // global font size base
const fs = (delta=0) => BASE + delta;

/* ── styles used repeatedly ── */
const cardBase = { border:"1px solid #e0e0e0", borderRadius:10, overflow:"hidden" };
const thStyle = { padding:"7px 8px", textAlign:"left", fontSize:fs(-1),
  fontWeight:500, color:"#666", background:"#f7f7f5", borderBottom:"1px solid #e0e0e0" };
const tdStyle = { padding:"8px 8px", fontSize:fs(), color:"#333", borderBottom:"0.5px solid #ebebeb" };

/* ── auto-number within dept view ── */
const autoNum = (reports, dept) => {
  let seq = 1;
  return reports.filter(r => r.dept === dept).map(r => ({ ...r, _seq: seq++ }));
};

/* ── Badge ── */
function Badge({ status }) {
  const s = SC[status] || SC["No activities"];
  return (
    <span style={{ display:"inline-flex", alignItems:"center", gap:4,
      padding:"2px 8px", borderRadius:20, fontSize:fs(-1), fontWeight:500,
      background:s.bg, color:s.c, border:`0.5px solid ${s.bd}`, whiteSpace:"nowrap" }}>
      <span style={{ width:6, height:6, borderRadius:"50%", background:s.dot, flexShrink:0 }}/>
      {status}
    </span>
  );
}

/* ── Overlay ── */
function Overlay({ onClose, children, wide }) {
  return (
    <div onClick={e => e.target===e.currentTarget && onClose()}
      style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.45)",
        display:"flex", alignItems:"center", justifyContent:"center", zIndex:1000 }}>
      <div style={{ background:"#fff", borderRadius:14, width:wide?700:560,
        maxWidth:"96vw", maxHeight:"90vh", overflow:"auto", padding:"22px 26px",
        boxShadow:"0 8px 40px rgba(0,0,0,.2)", border:"1px solid #d0d0d0",
        fontSize:fs() }}>
        {children}
      </div>
    </div>
  );
}

/* ── Summary ── */
function SummaryView({ reports, approvals }) {
  const deptRows = DEPTS.map(dept => {
    const rs = reports.filter(r => r.dept === dept);
    const c = counts(rs);
    const pct = rs.length ? Math.round(c._onTrackEff / rs.length * 100) : 0;
    return { dept, total:rs.length, ...c, pct };
  });
  const totals = deptRows.reduce((a,r) => ({
    total: a.total + r.total,
    "On-Track": a["On-Track"] + r["On-Track"],
    "Risk of delay": a["Risk of delay"] + r["Risk of delay"],
    "High risk": a["High risk"] + r["High risk"],
    "No activities": a["No activities"] + r["No activities"],
    _onTrackEff: a._onTrackEff + r._onTrackEff,
  }), { total:0,"On-Track":0,"Risk of delay":0,"High risk":0,"No activities":0,_onTrackEff:0 });
  const overallPct = totals.total ? Math.round(totals._onTrackEff / totals.total * 100) : 0;
  const printTimestamp = new Date().toLocaleString("en-GB", {
    day:"2-digit", month:"short", year:"numeric", hour:"2-digit", minute:"2-digit"
  });

  return (
    <div>
      {/* Timestamp */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
        <div style={{ fontSize:fs(-1), color:"#888" }}>
          Report generated: <span style={{ fontWeight:500, color:"#555" }}>{printTimestamp}</span>
        </div>
      </div>

      {/* KPI cards */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:10, marginBottom:18 }}>
        {ST.map(s => {
          const st = SC[s]; const n = totals[s];
          return (
            <div key={s} style={{ background:st.bg, border:`1px solid ${st.bd}`, borderRadius:12, padding:"12px 14px" }}>
              <div style={{ fontSize:28, fontWeight:500, color:st.c, lineHeight:1 }}>{n}</div>
              <div style={{ fontSize:fs(-1), color:st.c, marginTop:4, opacity:.85 }}>{s}</div>
              {s==="No activities" && (
                <div style={{ fontSize:10, color:st.c, opacity:.6, marginTop:1 }}>counted as On-Track</div>
              )}
            </div>
          );
        })}
      </div>

      {/* Progress bar */}
      <div style={{ marginBottom:16 }}>
        <div style={{ display:"flex", justifyContent:"space-between", fontSize:fs(-1), marginBottom:5 }}>
          <span style={{ color:"#666" }}>Overall compliance (On-Track + No activities)</span>
          <span style={{ fontWeight:500, color:overallPct===100?"#2D5A0E":"#333" }}>
            {totals._onTrackEff}/{totals.total} ({overallPct}%)
          </span>
        </div>
        <div style={{ height:7, background:"#eee", borderRadius:4, overflow:"hidden" }}>
          <div style={{ height:"100%", width:`${overallPct}%`,
            background:overallPct===100?"#639922":"#378ADD", borderRadius:4, transition:"width .4s" }}/>
        </div>
      </div>

      {/* Dept table */}
      <div style={cardBase}>
        <table style={{ width:"100%", borderCollapse:"collapse", tableLayout:"fixed", fontSize:fs() }}>
          <thead>
            <tr>
              <th style={{ ...thStyle, width:"auto", textAlign:"left" }}>Department</th>
              <th style={{ ...thStyle, width:50, textAlign:"center" }}>Total</th>
              {ST.map(s => (
                <th key={s} style={{ ...thStyle, width:82, textAlign:"center",
                  color:SC[s].c, background:SC[s].bg+"80" }}>{s}</th>
              ))}
              <th style={{ ...thStyle, width:88, textAlign:"center" }}>Progress</th>
            </tr>
          </thead>
          <tbody>
            {deptRows.map((r,i) => (
              <tr key={r.dept} style={{ background:i%2===0?"#fff":"#fafaf8" }}>
                <td style={{ ...tdStyle, fontWeight:500, color:"#111" }}>{r.dept}</td>
                <td style={{ ...tdStyle, textAlign:"center" }}>{r.total}</td>
                {ST.map(s => (
                  <td key={s} style={{ ...tdStyle, textAlign:"center",
                    color:r[s]>0?SC[s].c:"#bbb", fontWeight:r[s]>0?500:400,
                    background:r[s]>0?SC[s].bg+"60":"transparent" }}>
                    {r[s]>0?r[s]:"—"}
                  </td>
                ))}
                <td style={{ ...tdStyle }}>
                  <div style={{ display:"flex", alignItems:"center", gap:5 }}>
                    <div style={{ flex:1, height:5, background:"#eee", borderRadius:3, overflow:"hidden" }}>
                      <div style={{ height:"100%", width:`${r.pct}%`,
                        background:r.pct===100?"#639922":"#378ADD", borderRadius:3 }}/>
                    </div>
                    <span style={{ fontSize:10, color:"#888", minWidth:28, textAlign:"right" }}>{r.pct}%</span>
                  </div>
                </td>
              </tr>
            ))}
            <tr style={{ background:"#f3f3f0", borderTop:"1.5px solid #ccc" }}>
              <td style={{ ...tdStyle, fontWeight:600, color:"#111" }}>Total (SCCC-CLC)</td>
              <td style={{ ...tdStyle, textAlign:"center", fontWeight:600 }}>{totals.total}</td>
              {ST.map(s => (
                <td key={s} style={{ ...tdStyle, textAlign:"center", fontWeight:600,
                  color:SC[s].c, background:SC[s].bg+"80" }}>{totals[s]}</td>
              ))}
              <td style={{ ...tdStyle, textAlign:"center", fontSize:fs(-1), fontWeight:500, color:"#444" }}>
                {overallPct}%
              </td>
            </tr>
          </tbody>
        </table>
      </div>

      {/* Approvals */}
      {approvals.length>0 && (
        <div style={{ marginTop:22 }}>
          <div style={{ fontSize:fs(1), fontWeight:500, marginBottom:10, color:"#111" }}>
            Approval responses
          </div>
          <div style={cardBase}>
            <table style={{ width:"100%", borderCollapse:"collapse", fontSize:fs() }}>
              <thead>
                <tr>
                  {["Approver","Response","Time","Comment"].map(h => (
                    <th key={h} style={{ ...thStyle, textAlign:"left" }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {approvals.map((a,i) => (
                  <tr key={i} style={{ background:i%2===0?"#fff":"#fafaf8", borderBottom:"0.5px solid #ebebeb" }}>
                    <td style={{ ...tdStyle, fontWeight:500 }}>{a.email}</td>
                    <td style={{ ...tdStyle }}>
                      <span style={{ display:"inline-flex", alignItems:"center", gap:4,
                        fontSize:fs(-1), padding:"2px 8px", borderRadius:20, fontWeight:500,
                        background:a.response==="Approved"?"#EAF3DE":a.response==="Rejected"?"#FCEBEB":"#F1EFE8",
                        color:a.response==="Approved"?"#2D5A0E":a.response==="Rejected"?"#8B2020":"#4A4944" }}>
                        {a.response==="Approved"?"✓ Approved":a.response==="Rejected"?"✗ Rejected":"⏳ Pending"}
                      </span>
                    </td>
                    <td style={{ ...tdStyle, color:"#777" }}>{a.respondedAt||"—"}</td>
                    <td style={{ ...tdStyle, color:"#555" }}>{a.comment||"—"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div style={{ marginTop:6, fontSize:fs(-1), color:"#888" }}>
            {approvals.filter(a=>a.response==="Approved").length} of {approvals.length} approved
          </div>
        </div>
      )}
    </div>
  );
}

/* ── Edit Modal ── */
function EditModal({ report, dept, onSave, onClose }) {
  const isNew = !report?.id;
  const [form, setForm] = useState(report ? { ...report } : {
    dept: dept||DEPTS[0], plant:"", nameEN:"", nameTH:"",
    regulator:"", frequency:"Yearly", deadline:"",
    responsible:"", department:"", contact:"",
    status:"On-Track", updatedDate:today(), lastSubmit:"", expiry:"", remark:""
  });
  const set = (k,v) => setForm(f => ({ ...f, [k]:v }));

  const field = (label, key, type="text", opts) => (
    <div style={{ marginBottom:11 }}>
      <label style={{ display:"block", fontSize:fs(-1), color:"#666", marginBottom:3 }}>{label}</label>
      {opts
        ? <select value={form[key]||""} onChange={e=>set(key,e.target.value)}
            style={{ width:"100%", fontSize:fs(), background:"#fff" }}>
            {opts.map(o=><option key={o}>{o}</option>)}
          </select>
        : type==="ta"
          ? <textarea value={form[key]||""} onChange={e=>set(key,e.target.value)} rows={2}
              style={{ width:"100%", boxSizing:"border-box", fontSize:fs(), background:"#fff" }}/>
          : <input type={type} value={form[key]||""} onChange={e=>set(key,e.target.value)}
              style={{ width:"100%", boxSizing:"border-box", fontSize:fs(), background:"#fff" }}/>
      }
    </div>
  );

  return (
    <Overlay onClose={onClose}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
        <div style={{ fontSize:fs(2), fontWeight:500, color:"#111" }}>
          {isNew?"Add new report":"Edit report"}
        </div>
        <button onClick={onClose} style={{ background:"none", border:"none", fontSize:20,
          cursor:"pointer", color:"#888", lineHeight:1 }}>×</button>
      </div>

      {/* Dept selector — no auto-number input */}
      {field("Department","dept","text",DEPTS)}
      {field("Report name (English)","nameEN")}
      {field("Report name (Thai)","nameTH")}
      {field("Regulator","regulator")}
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"0 12px" }}>
        {field("Frequency","frequency","text",["Monthly","Quarterly","Every 6 months","Yearly","Every 3 years","Every 5 years","As occur","As change"])}
        {field("Submission deadline","deadline")}
      </div>
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"0 12px" }}>
        {field("Responsible person","responsible")}
        {field("Department / Function","department")}
      </div>
      {field("Contact person","contact")}
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:"0 12px" }}>
        {field("Status","status","text",ST)}
        {field("Last submission","lastSubmit","date")}
        {field("Expiry date","expiry","date")}
      </div>
      {field("Remark / latest information","remark","ta")}

      <div style={{ display:"flex", gap:8, justifyContent:"flex-end", marginTop:8 }}>
        <button onClick={onClose}
          style={{ fontSize:fs(), padding:"6px 16px", background:"#f5f5f5",
            border:"1px solid #ddd", color:"#444", borderRadius:6, cursor:"pointer" }}>
          Cancel
        </button>
        <button onClick={() => onSave({ ...form, displayName:form.nameEN||form.nameTH, updatedDate:today() })}
          style={{ fontSize:fs(), padding:"6px 18px", background:"#1a6fd4", color:"#fff",
            border:"none", fontWeight:500, borderRadius:6, cursor:"pointer" }}>
          Save
        </button>
      </div>
    </Overlay>
  );
}

/* ── Email Modal ── */
function EmailModal({ reports, approvals, senderEmail, onClose, onSendComplete }) {
  const [recipients, setRecipients] = useState(
    approvals.map(a=>a.email).join("\n")
  );
  const [subject, setSubject] = useState(
    "Statutory Report Status Update — Action Required"
  );
  const [body, setBody] = useState("");
  const [loading, setLoading] = useState(false);
  const [sent, setSent] = useState(false);
  const [copied, setCopied] = useState(false);
  const copyRef = useRef(null);

  const c = counts(reports);
  const attn = reports.filter(r => r.status==="Risk of delay"||r.status==="High risk");
  const emailList = () => recipients.split(/[\n,;]+/).map(e=>e.trim()).filter(Boolean);

  const generate = async () => {
    setLoading(true); setBody("");
    try {
      const summary = reports.map(r =>
        `[${DEPT_SHORT[r.dept]||r.dept}|#${r._seq||r.no}] ${r.displayName} | ${r.status}${r.remark?" | "+r.remark:""}`
      ).join("\n");
      const attnList = attn.length
        ? attn.map(r=>`- [${r.dept}] ${r.displayName} → ${r.status}${r.remark?" ("+r.remark+")":""}`).join("\n")
        : "None — all active reports are On-Track or No activities.";

      const prompt = `Write a statutory compliance approval email.

From: ${senderEmail||"compliance@company.com"}
Date: ${today()}
Company: SCCC-CLC
Reports: ${reports.length} total | On-Track: ${c["On-Track"]} | No activities: ${c["No activities"]} | Risk of delay: ${c["Risk of delay"]} | High risk: ${c["High risk"]}

Items needing attention:
${attnList}

Full report list:
${summary}

Write a professional email body (no subject line). Include:
1. Brief compliance status summary (2–3 sentences)  
2. Items needing attention if any
3. Clear instruction: reply with "APPROVE" or "REJECT [reason]" — responses recorded in compliance system
4. Sign-off from Compliance Team / ${senderEmail||"compliance@company.com"}
English, formal, concise.`;

      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:1000,
          messages:[{ role:"user", content:prompt }] })
      });
      const data = await res.json();
      setBody(data.content?.[0]?.text || "Error generating email.");
    } catch { setBody("Connection error. Please try again."); }
    setLoading(false);
  };

  const handleSend = () => {
    const emails = emailList();
    if (!emails.length) { alert("Please enter at least one recipient."); return; }
    const newApprovals = emails.map(email => ({
      email, response:"Pending", respondedAt:null, comment:null,
    }));
    onSendComplete(newApprovals);
    setSent(true);
  };

  const openMailto = () => {
    const emails = emailList();
    if (!emails.length) return;
    const mailto = `mailto:${emails.join(",")}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    window.open(mailto);
  };

  const copy = () => {
    const el = copyRef.current;
    if (!el) return;
    el.value = `Subject: ${subject}\n\n${body}`;
    el.style.display = "block";
    el.select();
    el.setSelectionRange(0, 99999);
    try {
      document.execCommand("copy");
      setCopied(true);
      setTimeout(() => setCopied(false), 2500);
    } catch {}
    el.style.display = "none";
  };

  if (sent) return (
    <Overlay onClose={onClose}>
      <div style={{ textAlign:"center", padding:"24px 0", fontSize:fs() }}>
        <div style={{ fontSize:44, marginBottom:14 }}>✓</div>
        <div style={{ fontSize:fs(3), fontWeight:500, marginBottom:10 }}>Approval requests logged</div>
        <div style={{ fontSize:fs(), color:"#666", marginBottom:24, lineHeight:1.7 }}>
          {emailList().length} recipients added to approval tracking.<br/>
          Open your email client and send the copied email — replies<br/>
          can be recorded manually in the Summary tab.
        </div>
        <button onClick={onClose}
          style={{ background:"#1a6fd4", color:"#fff", border:"none", fontWeight:500,
            padding:"8px 22px", borderRadius:8, cursor:"pointer", fontSize:fs() }}>
          Done
        </button>
      </div>
    </Overlay>
  );

  return (
    <Overlay onClose={onClose} wide>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
        <div style={{ fontSize:fs(2), fontWeight:500, color:"#111" }}>Send approval request</div>
        <button onClick={onClose} style={{ background:"none", border:"none", fontSize:20,
          cursor:"pointer", color:"#888" }}>×</button>
      </div>

      {attn.length>0 && (
        <div style={{ background:"#FAEEDA", border:"1px solid #FAC775", borderRadius:8,
          padding:"9px 13px", marginBottom:14, fontSize:fs(), color:"#7A4A08" }}>
          ⚠ {attn.length} report(s) need attention — included in email
        </div>
      )}

      {/* Status strip */}
      <div style={{ display:"flex", gap:7, marginBottom:16, flexWrap:"wrap" }}>
        {ST.map(s => (
          <span key={s} style={{ fontSize:fs(-1), padding:"3px 9px", borderRadius:20,
            background:SC[s].bg, color:SC[s].c, border:`0.5px solid ${SC[s].bd}`, fontWeight:500 }}>
            {c[s]} {s}
          </span>
        ))}
      </div>

      {/* Sender */}
      <div style={{ marginBottom:12, padding:"10px 13px", background:"#f0f6ff",
        border:"1px solid #c5daff", borderRadius:8, fontSize:fs() }}>
        <span style={{ color:"#666" }}>Sending from: </span>
        <span style={{ fontWeight:500, color:"#1a4a8a" }}>{senderEmail||"(not set — configure in Settings)"}</span>
      </div>

      {/* Recipients */}
      <div style={{ marginBottom:12 }}>
        <label style={{ display:"block", fontSize:fs(-1), color:"#666", marginBottom:3 }}>
          Recipients — one per line or comma separated (up to 25)
        </label>
        <textarea value={recipients} onChange={e=>setRecipients(e.target.value)} rows={5}
          placeholder={"approver1@company.com\napprover2@company.com\n..."}
          style={{ width:"100%", boxSizing:"border-box", background:"#fff",
            fontFamily:"var(--font-mono)", fontSize:fs(-1) }}/>
        <div style={{ fontSize:10, color:"#888", marginTop:3 }}>
          {emailList().length} recipients
        </div>
      </div>

      {/* Subject */}
      <div style={{ marginBottom:12 }}>
        <label style={{ display:"block", fontSize:fs(-1), color:"#666", marginBottom:3 }}>Subject</label>
        <input value={subject} onChange={e=>setSubject(e.target.value)}
          style={{ width:"100%", boxSizing:"border-box", fontSize:fs(), background:"#fff" }}/>
      </div>

      {/* Generate + actions */}
      <div style={{ display:"flex", gap:8, marginBottom:12, flexWrap:"wrap" }}>
        <button onClick={generate} disabled={loading}
          style={{ fontSize:fs(), padding:"6px 14px", background:"#1a6fd4", color:"#fff",
            border:"none", fontWeight:500, borderRadius:6, cursor:"pointer" }}>
          {loading?"Generating…":"Generate email body ↗"}
        </button>
        {body && <>
          {/* hidden textarea used as copy buffer */}
          <textarea ref={copyRef} readOnly
            style={{ position:"fixed", top:-9999, left:-9999, display:"none",
              opacity:0, width:1, height:1 }}/>
          <button onClick={copy}
            style={{ fontSize:fs(), padding:"6px 13px", borderRadius:6, cursor:"pointer",
              background: copied?"#EAF3DE":"#fff",
              color: copied?"#2D5A0E":"#333",
              border: copied?"1px solid #C0DD97":"1px solid #ddd",
              fontWeight: copied?500:400 }}>
            {copied ? "✓ Copied!" : "Copy email"}
          </button>
          <button onClick={openMailto}
            style={{ fontSize:fs(), padding:"6px 13px", background:"#fff",
              border:"1px solid #1a6fd4", color:"#1a6fd4", borderRadius:6, cursor:"pointer", fontWeight:500 }}>
            Open in Mail app ↗
          </button>
        </>}
      </div>

      {/* Body */}
      {body && (
        <div style={{ marginBottom:14 }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:3 }}>
            <label style={{ fontSize:fs(-1), color:"#666" }}>Email body (editable)</label>
            <span style={{ fontSize:10, color:"#999" }}>Click inside → Ctrl+A / Cmd+A to select all, then Ctrl+C / Cmd+C to copy</span>
          </div>
          <textarea value={body} onChange={e=>setBody(e.target.value)} rows={11}
            onClick={e => { e.target.select(); }}
            style={{ width:"100%", boxSizing:"border-box", background:"#fff",
              fontSize:fs(), lineHeight:1.7, fontFamily:"inherit" }}/>
        </div>
      )}

      {/* Simulate responses */}
      {body && (
        <div style={{ background:"#f7f7f5", border:"1px solid #e0e0e0", borderRadius:10,
          padding:"14px 16px", marginBottom:16 }}>
          <div style={{ fontSize:fs(), fontWeight:500, color:"#333", marginBottom:5 }}>
            Simulate approval responses
          </div>
          <div style={{ fontSize:fs(-1), color:"#777", marginBottom:10 }}>
            Test the approval tracking flow — responses appear in the Summary tab.
          </div>
          <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
            <button onClick={() => {
              const mocks = emailList().map(email => ({
                email, response:"Approved", respondedAt:nowTs(), comment:"Approved"
              }));
              onSendComplete(mocks); setSent(true);
            }} style={{ fontSize:fs(-1), padding:"5px 12px", background:"#EAF3DE",
              color:"#2D5A0E", border:"1px solid #C0DD97", borderRadius:6, cursor:"pointer" }}>
              ✓ All approve
            </button>
            <button onClick={() => {
              const mocks = emailList().map((email,i) => ({
                email, response:i%4===0?"Rejected":"Approved",
                respondedAt:nowTs(), comment:i%4===0?"Needs revision":"OK"
              }));
              onSendComplete(mocks); setSent(true);
            }} style={{ fontSize:fs(-1), padding:"5px 12px", background:"#FAEEDA",
              color:"#7A4A08", border:"1px solid #FAC775", borderRadius:6, cursor:"pointer" }}>
              ⚠ Mixed responses
            </button>
          </div>
        </div>
      )}

      <div style={{ display:"flex", gap:8, justifyContent:"flex-end" }}>
        <button onClick={onClose}
          style={{ fontSize:fs(), padding:"6px 16px", background:"#f5f5f5",
            border:"1px solid #ddd", color:"#444", borderRadius:6, cursor:"pointer" }}>
          Cancel
        </button>
        <button onClick={handleSend}
          style={{ fontSize:fs(), padding:"6px 18px", background:"#1a6fd4", color:"#fff",
            border:"none", fontWeight:500, borderRadius:6, cursor:"pointer" }}>
          Log {emailList().length} recipient(s) as pending
        </button>
      </div>
    </Overlay>
  );
}

